// // This module implements a 4-bit shift register that shifts bits to the right on every clock cycle, with the ability to load a new value when the load signal is low. The register has a synchronous reset that sets the register to all ones. The inputs are clk, load, reset, and a 4-bit data input. The output is a 4-bit q which represents the current value of the shift register.
module shift_register (  
    input clk,  
    input load,  
    input reset,  
    input [3:0] data,  
    output reg [3:0] q  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            q <= 4'b0000;  
        else if (load)  
            q <= data;  
        else  
            q <= {q[2:0], 1'b0};  
    end  
endmodule
